<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'; import PageHeader from '@/components/PageHeader.vue'; import type { ImportResult, Student } from '@/types'; import { createStudent, deleteStudent, getStudents, importStudents, updateStudent } from '@/api/students'; import { ElMessage, ElMessageBox, type UploadFile } from 'element-plus'
const loading=ref(false),dialog=ref(false),importDialog=ref(false),rows=ref<Student[]>([]),total=ref(0),selectedFile=ref<File>(),importResult=ref<ImportResult>();const selectedRows=ref<Student[]>([]),batchDeleting=ref(false);const query=reactive({current:1,size:10,keyword:'',status:''});const form=reactive<Student>({student_id:0,student_no:'',student_name:'',college:'',major:'',class_name:''});const importForm=reactive({batch_name:'',template_id:1})
async function load(){loading.value=true;try{const p=await getStudents(query);rows.value=p.records;total.value=p.total}catch{rows.value=[]}finally{loading.value=false}}function reset(){query.keyword='';query.current=1;load()}function open(row?:Student){Object.assign(form,row||{student_id:0,student_no:'',student_name:'',college:'',major:'',class_name:''});dialog.value=true}
async function save(){if(!form.student_no||!form.student_name)return ElMessage.warning('请填写学号和姓名');if(form.student_id)await updateStudent(form.student_id,form);else await createStudent(form);ElMessage.success('保存成功');dialog.value=false;load()}async function remove(row:Student){await ElMessageBox.confirm(`确认删除学生“${row.student_name}”吗？`,'删除学生',{type:'warning'});await deleteStudent(row.student_id);ElMessage.success('删除成功');load()}
function handleSelectionChange(selection:Student[]){selectedRows.value=selection}
async function removeSelected(){
 if(!selectedRows.value.length)return ElMessage.warning('请先选择要删除的学生');
 await ElMessageBox.confirm(`确认删除选中的 ${selectedRows.value.length} 名学生吗？此操作不可恢复。`,'批量删除',{type:'warning'});
 batchDeleting.value=true;
 try{
  const results=await Promise.allSettled(selectedRows.value.map(row=>deleteStudent(row.student_id)));
  const successCount=results.filter(result=>result.status==='fulfilled').length;
  const failedCount=results.length-successCount;
  selectedRows.value=[];
  if(successCount&&failedCount)ElMessage.warning(`批量删除完成：成功 ${successCount} 条，失败 ${failedCount} 条`);
  else if(successCount)ElMessage.success(`已删除 ${successCount} 名学生`);
  else ElMessage.error('批量删除失败');
  await load();
 }finally{batchDeleting.value=false;}
}
function choose(file:UploadFile){selectedFile.value=file.raw}async function upload(){if(!selectedFile.value)return ElMessage.warning('请选择Excel文件');importResult.value=await importStudents(selectedFile.value,importForm.batch_name,importForm.template_id);ElMessage.success('导入完成');load()}
onMounted(load)
</script>
<template><div><PageHeader title="学生管理" description="维护学生档案并导入实训名单"><el-button @click="importDialog=true">Excel导入</el-button><el-button type="primary" @click="open()">新增学生</el-button></PageHeader><section class="panel"><div class="toolbar"><el-input v-model="query.keyword" placeholder="学号、姓名或班级" clearable style="width:260px" @keyup.enter="query.current=1;load()"/><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button><el-button type="danger" plain :disabled="!selectedRows.length" :loading="batchDeleting" @click="removeSelected">批量删除（{{selectedRows.length}}）</el-button></div><el-table v-loading="loading" :data="rows" @selection-change="handleSelectionChange" empty-text="暂无学生数据"><el-table-column type="selection" width="52"/><el-table-column prop="student_no" label="学号"/><el-table-column prop="student_name" label="姓名"/><el-table-column prop="college" label="学院"/><el-table-column prop="major" label="专业"/><el-table-column prop="class_name" label="班级"/><el-table-column label="操作" width="150"><template #default="s"><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" :page-sizes="[10,20,50]" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-dialog v-model="dialog" :title="form.student_id?'编辑学生':'新增学生'" width="560"><el-form label-position="top"><div class="form-grid"><el-form-item label="学号" required><el-input v-model="form.student_no"/></el-form-item><el-form-item label="姓名" required><el-input v-model="form.student_name"/></el-form-item><el-form-item label="学院"><el-input v-model="form.college"/></el-form-item><el-form-item label="专业"><el-input v-model="form.major"/></el-form-item></div><el-form-item label="班级"><el-input v-model="form.class_name"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog><el-dialog v-model="importDialog" title="导入学生名单" width="620"><el-form label-position="top"><div class="form-grid"><el-form-item label="批次名称"><el-input v-model="importForm.batch_name"/></el-form-item><el-form-item label="模板ID"><el-input-number v-model="importForm.template_id" :min="1"/></el-form-item></div></el-form><el-upload drag :auto-upload="false" :limit="1" accept=".xlsx,.xls" @change="choose"><div class="upload-title">拖入Excel文件或点击选择</div></el-upload><el-alert v-if="importResult" class="import-result" :title="`成功 ${importResult.success_count} 条，失败 ${importResult.failed_count} 条`" :description="importResult.failures.map(x=>`第${x.row}行：${x.reason}`).join('；')||'全部导入成功'" :type="importResult.failed_count?'warning':'success'" show-icon/><template #footer><el-button @click="importDialog=false">关闭</el-button><el-button type="primary" @click="upload">开始导入</el-button></template></el-dialog></div></template>